(function(){"use strict";function f(n){try{return"/"+(new URL(n).pathname.split("/").filter(Boolean)[0]||"")}catch{return"/"}}self.onmessage=({data:n})=>{if(n.type!=="clear"){if(n.type==="process"){const{nodes:c,edges:r}=n,o={};for(let e=0;e<c.length;e++)o[c[e].id]=e;const s={},t={};for(const e of r)t[e.source]||(t[e.source]=[]),t[e.source].push(e.target),s[e.target]||(s[e.target]=[]),s[e.target].push(e.source);self.postMessage({type:"processed",inlinks:s,outlinks:t,urlToIndex:o,edgeCount:r.length})}if(n.type==="bundle"){const{edges:c,minCount:r}=n,o=new Map;for(const t of c){const e=f(t.source),u=f(t.target);if(e===u)continue;const i=`${e}\0${u}`;o.set(i,(o.get(i)||0)+1)}const s=[];for(const[t,e]of o){if(e<r)continue;const[u,i]=t.split("\0");s.push({sourcePrefix:u,targetPrefix:i,count:e})}s.sort((t,e)=>e.count-t.count),self.postMessage({type:"bundled",bundles:s})}}}})();
